{
  "name": "ai-cockpit",
  "displayName": "AI Cockpit",
  "description": "Monitor and manage Claude Code tasks with real-time diff tracking",
  "version": "0.1.0",
  "publisher": "ai-cockpit",
  "engines": {
    "vscode": "^1.85.0"
  },
  "categories": [
    "Other"
  ],
  "activationEvents": [
    "workspaceContains:.ai/cockpit"
  ],
  "main": "./dist/extension.js",
  "contributes": {
    "commands": [
      {
        "command": "aiCockpit.showPanel",
        "title": "AI Cockpit: Show Panel"
      },
      {
        "command": "aiCockpit.refresh",
        "title": "AI Cockpit: Refresh"
      },
      {
        "command": "aiCockpit.showTaskMenu",
        "title": "AI Cockpit: Show Task Menu"
      },
      {
        "command": "aiCockpit.viewEventDiff",
        "title": "AI Cockpit: View Event Diff"
      },
      {
        "command": "aiCockpit.showClaudeChanges",
        "title": "AI Cockpit: Show Claude Changes"
      },
      {
        "command": "aiCockpit.showYourChanges",
        "title": "AI Cockpit: Show Your Changes"
      },
      {
        "command": "aiCockpit.showFullDiff",
        "title": "AI Cockpit: Show Full Diff"
      },
      {
        "command": "aiCockpit.openTaskTerminal",
        "title": "AI Cockpit: Open Task Terminal",
        "icon": "$(terminal)"
      },
      {
        "command": "aiCockpit.resumeSession",
        "title": "AI Cockpit: Resume Session",
        "icon": "$(play)"
      },
      {
        "command": "aiCockpit.focusSession",
        "title": "AI Cockpit: Focus Session",
        "icon": "$(eye)"
      },
      {
        "command": "aiCockpit.newSession",
        "title": "AI Cockpit: New Session",
        "icon": "$(add)"
      },
      {
        "command": "aiCockpit.cleanupSessions",
        "title": "AI Cockpit: Cleanup Old Sessions"
      },
      {
        "command": "aiCockpit.validateClaudePath",
        "title": "AI Cockpit: Validate Claude Path"
      },
      {
        "command": "aiCockpit.openTask",
        "title": "AI Cockpit: Open Task"
      },
      {
        "command": "aiCockpit.openWorkItem",
        "title": "AI Cockpit: Open Work Item"
      },
      {
        "command": "aiCockpit.renameSession",
        "title": "Rename Session",
        "icon": "$(edit)"
      },
      {
        "command": "aiCockpit.deleteSession",
        "title": "Delete Session",
        "icon": "$(trash)"
      },
      {
        "command": "aiCockpit.startSession",
        "title": "AI Cockpit: Start Session",
        "icon": "$(add)"
      },
      {
        "command": "aiCockpit.linkSessionToTask",
        "title": "Link to Task",
        "icon": "$(link)"
      }
    ],
    "configuration": {
      "title": "AI Cockpit",
      "properties": {
        "aiCockpit.sessions.retentionDays": {
          "type": "number",
          "default": 7,
          "description": "Number of days to keep closed sessions"
        },
        "aiCockpit.sessions.autoCleanup": {
          "type": "boolean",
          "default": true,
          "description": "Automatically clean up old sessions on startup"
        },
        "aiCockpit.claude.historyPath": {
          "type": "string",
          "default": "",
          "description": "Path to Claude's history.jsonl file. Leave empty to use default (~/.claude/history.jsonl)"
        },
        "aiCockpit.claude.autoDetect": {
          "type": "boolean",
          "default": true,
          "description": "Automatically detect Claude history location"
        }
      }
    },
    "viewsContainers": {
      "activitybar": [
        {
          "id": "ai-cockpit",
          "title": "AI Cockpit",
          "icon": "media/icon.svg"
        }
      ]
    },
    "views": {
      "ai-cockpit": [
        {
          "id": "aiCockpit.tasks",
          "name": "Tasks"
        }
      ]
    },
    "menus": {
      "view/item/context": [
        {
          "command": "aiCockpit.openTaskTerminal",
          "when": "view == aiCockpit.tasks && viewItem == task-in_progress",
          "group": "inline"
        },
        {
          "command": "aiCockpit.openTaskTerminal",
          "when": "view == aiCockpit.tasks && viewItem == task-active",
          "group": "inline"
        },
        {
          "command": "aiCockpit.openTaskTerminal",
          "when": "view == aiCockpit.tasks && viewItem == task-todo",
          "group": "inline"
        },
        {
          "command": "aiCockpit.openTaskTerminal",
          "when": "view == aiCockpit.tasks && viewItem == task-done",
          "group": "inline"
        },
        {
          "command": "aiCockpit.viewEventDiff",
          "when": "view == aiCockpit.tasks && viewItem == event",
          "group": "inline"
        },
        {
          "command": "aiCockpit.showClaudeChanges",
          "when": "view == aiCockpit.tasks && viewItem =~ /shadow-file/",
          "group": "navigation@1"
        },
        {
          "command": "aiCockpit.showYourChanges",
          "when": "view == aiCockpit.tasks && viewItem == shadow-file-user-modified",
          "group": "navigation@2"
        },
        {
          "command": "aiCockpit.showFullDiff",
          "when": "view == aiCockpit.tasks && viewItem =~ /shadow-file/",
          "group": "navigation@3"
        },
        {
          "command": "aiCockpit.focusSession",
          "when": "view == aiCockpit.tasks && viewItem == session-active",
          "group": "inline"
        },
        {
          "command": "aiCockpit.resumeSession",
          "when": "view == aiCockpit.tasks && viewItem == session-closed",
          "group": "inline"
        },
        {
          "command": "aiCockpit.newSession",
          "when": "view == aiCockpit.tasks && viewItem == sessions-section",
          "group": "inline"
        },
        {
          "command": "aiCockpit.renameSession",
          "when": "view == aiCockpit.tasks && viewItem == session-active",
          "group": "2_session@1"
        },
        {
          "command": "aiCockpit.renameSession",
          "when": "view == aiCockpit.tasks && viewItem == session-closed",
          "group": "2_session@1"
        },
        {
          "command": "aiCockpit.deleteSession",
          "when": "view == aiCockpit.tasks && viewItem == session-active",
          "group": "2_session@2"
        },
        {
          "command": "aiCockpit.deleteSession",
          "when": "view == aiCockpit.tasks && viewItem == session-closed",
          "group": "2_session@2"
        }
      ]
    }
  },
  "scripts": {
    "vscode:prepublish": "npm run compile",
    "compile": "tsc -p ./",
    "watch": "tsc -watch -p ./",
    "lint": "eslint src --ext ts"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/vscode": "^1.85.0",
    "@typescript-eslint/eslint-plugin": "^6.0.0",
    "@typescript-eslint/parser": "^6.0.0",
    "eslint": "^8.0.0",
    "typescript": "^5.0.0"
  },
  "dependencies": {
    "@vscode/vsce": "^3.7.1"
  }
}
